1019→export function useProject() {
1020→  const ctx = useContext(ProjectContext);
1021→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
1022→  const { state, dispatch } = ctx;
1023→
1024→  const duplicateFloor = (floorId) => {
1025→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
1026→    return floor ? createDuplicatedFloor(floor) : null;
1027→  };
1028→
1029→  return {
1030→    project: state.project,
1031→    isDirty: state.isDirty,
1032→    lastSavedAt: state.lastSavedAt,
1033→    canUndo: state.history.length > 0,
1034→    canRedo: state.future.length > 0,
1035→    dispatch,
1036→    duplicateFloor,
1037→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
1038→  };
1039→}
