166→export default function SheetViewportContent({ source }) {
167→  if (!source || source.kind === 'empty') return null;
168→
169→  if (source.kind === 'plan') {
170→    return <PlanViewportContent floor={source.floor} />;
171→  }
172→
173→  if (source.kind === 'roof_plan') {
174→    return <RoofRenderer roofSystem={source.roofSystem} interactive={false} />;
175→  }
176→
177→  if (source.kind === 'truss_plan') {
178→    return <TrussRenderer floor={source.floor} trussSystems={source.trussSystems} />;
179→  }
180→
181→  if (source.kind === 'truss_detail') {
182→    return (
183→      <TrussDetailRenderer
184→        trussSystem={source.trussSystem}
185→        trussInstanceId={source.trussInstanceId}
186→        showTitle={false}
187→      />
188→    );
189→  }
190→
191→  if (source.kind === 'roof_drainage') {
192→    return <RoofDrainageRenderer roofSystem={source.roofSystem} interactive={false} />;
193→  }
194→
195→  if (source.kind === 'roof_schedule') {
196→    return <RoofScheduleRenderer schedule={source.schedule} showTitle={false} />;
197→  }
198→
199→  if (source.kind === '3d_preview') {
200→    return <ThreePreviewViewportContent source={source} />;
201→  }
202→
203→  if (source.kind === 'section' || source.kind === 'roof_section') {
204→    return <SectionSceneLayer scene={source.scene} showTitle={false} />;
205→  }
206→
207→  if (source.kind === 'elevation') {
208→    return (
209→      <ElevationSceneLayer
210→        scene={source.scene}
211→        annotationScene={source.annotationScene}
212→        showTitle={false}
213→      />
214→    );
215→  }
216→
217→  if (source.kind === 'roof_elevation') {
218→    return (
219→      <ElevationSceneLayer
220→        scene={source.scene}
221→        annotationScene={null}
222→        showTitle={false}
223→      />
224→    );
225→  }
226→
227→  return null;
228→}
