 18→function rectPoints(element) {
 19→  return [
 20→    `${element.left},${-element.top}`,
 21→    `${element.right},${-element.top}`,
 22→    `${element.right},${-element.bottom}`,
 23→    `${element.left},${-element.bottom}`,
 24→  ].join(' ');
 25→}
