 35→export default function ElevationSceneLayer({ scene, annotationScene, showTitle = true, selectedId = null, selectedType = null }) {
 36→  if (!scene) return null;
 37→
 38→  const titleX = (scene.bounds.minX + scene.bounds.maxX) / 2;
 39→  const titleY = -scene.bounds.maxZ - 500;
 40→  const drawables = [
 41→    ...scene.elements.map((element) => ({ shape: 'rect', ...element })),
 42→    ...(scene.polygonElements || []).map((element) => ({ shape: 'polygon', ...element })),
 43→    ...(scene.lineElements || []).map((element) => ({ shape: 'line', ...element })),
 44→  ].sort((a, b) => b.depth - a.depth);
 45→
 46→  return (
 47→    <g className="elevation">
 48→      {showTitle && (
 49→        <text
 50→          x={titleX}
 51→          y={titleY}
 52→          textAnchor="middle"
 53→          dominantBaseline="middle"
 54→          fill={DRAWING_GRAPHICS.annotation.textMuted}
 55→          fontSize={220}
 56→          fontFamily="var(--font-blueprint)"
 57→          style={{ pointerEvents: 'none' }}
 58→        >
 59→          {scene.title}
 60→        </text>
 61→      )}
 62→      {drawables.map((element) => {
 63→        const style = STYLE_MAP[element.style] || STYLE_MAP.wall;
 64→        const isSelected = (
 65→          (selectedType === 'trussInstance' && element.sourceId === selectedId)
 66→          || (selectedType === 'trussSystem' && element.systemId === selectedId)
 67→          || (element.category === selectedType && element.sourceId === selectedId)
 68→        );
 69→        if (element.shape === 'line') {
 70→          return (
 71→            <polyline
 72→              key={element.id}
 73→              points={linePoints(element)}
 74→              fill="none"
 75→              stroke={isSelected ? 'var(--color-selection)' : style.stroke}
 76→              strokeWidth={isSelected ? 1.5 : style.strokeWidth}
 77→              vectorEffect="non-scaling-stroke"
 78→            />
 79→          );
 80→        }
 81→        return element.shape === 'rect'
 82→          ? (
 83→            <polygon
 84→              key={element.id}
 85→              points={rectPoints(element)}
 86→              fill={style.fill}
 87→              stroke={isSelected ? 'var(--color-selection)' : style.stroke}
 88→              strokeWidth={isSelected ? 1.5 : style.strokeWidth}
 89→              vectorEffect="non-scaling-stroke"
 90→            />
 91→          )
 92→          : (
 93→            <polygon
 94→              key={element.id}
 95→              points={polygonPoints(element)}
 96→              fill={style.fill}
 97→              stroke={isSelected ? 'var(--color-selection)' : style.stroke}
 98→              strokeWidth={isSelected ? 1.5 : style.strokeWidth}
 99→              vectorEffect="non-scaling-stroke"
100→            />
101→          );
102→      })}
103→      {Number.isFinite(scene.groundLevel) && (
104→        <line
105→          x1={scene.bounds.minX - 500}
106→          y1={-scene.groundLevel}
107→          x2={scene.bounds.maxX + 500}
108→          y2={-scene.groundLevel}
109→          stroke={DRAWING_GRAPHICS.elevation.groundStroke}
110→          strokeWidth={0.8}
111→          strokeDasharray={DRAWING_GRAPHICS.elevation.groundDash}
112→          vectorEffect="non-scaling-stroke"
113→        />
114→      )}
115→      {annotationScene && (
116→        <BlueprintAnnotationLayer
117→          className="elevation-annotations"
118→          dimensions={annotationScene.dimensions}
119→        />
120→      )}
121→    </g>
122→  );
123→}
