  9→export default function RoofRenderer({ roofSystem, selectedId = null, selectedType = null, interactive = true }) {
 10→  if (!roofSystem) return null;
 11→
 12→  const scene = buildRoofPlanScene(roofSystem);
 13→  const { plan, arrows, tags } = scene;
 14→  const isRoofSelected = selectedType === 'roofSystem' && selectedId === roofSystem.id;
 15→  const isCustom = plan.roofType === 'custom';
 16→  const transitionEdges = (plan.roofEdges || []).filter((edge) => !['ridge', 'valley', 'hip'].includes(edge.edgeRole));
 17→
 18→  return (
 19→    <g className="roof-system">
 20→      {!isCustom && plan.surfacePath && (
 21→        <path
 22→          d={plan.surfacePath}
 23→          fill={DRAWING_GRAPHICS.plan.objectFill}
 24→          fillRule="evenodd"
 25→          stroke={isRoofSelected ? 'var(--color-selection)' : DRAWING_GRAPHICS.plan.objectStroke}
 26→          strokeWidth={isRoofSelected ? 1.4 : DRAWING_GRAPHICS.plan.objectStrokeWidth}
 27→          vectorEffect="non-scaling-stroke"
 28→        />
 29→      )}
 30→      {isCustom && plan.roofPlanes.map((plane) => {
 31→        const isSelectedPlane = selectedType === 'roofPlane' && selectedId === plane.id;
 32→        return (
 33→          <polygon
 34→            key={plane.id}
 35→            points={plane.points}
 36→            fill={DRAWING_GRAPHICS.plan.objectFill}
 37→            fillOpacity={isSelectedPlane ? 0.52 : 0.28}
 38→            stroke={isSelectedPlane ? 'var(--color-selection)' : DRAWING_GRAPHICS.plan.objectStroke}
 39→            strokeWidth={isSelectedPlane ? 1.4 : DRAWING_GRAPHICS.plan.objectStrokeWidth}
 40→            vectorEffect="non-scaling-stroke"
 41→          />
 42→        );
 43→      })}
 44→      {isCustom && plan.roofOutlinePath && (
 45→        <path
 46→          d={plan.roofOutlinePath}
 47→          fill="none"
 48→          stroke={isRoofSelected ? 'var(--color-selection)' : DRAWING_GRAPHICS.plan.objectStroke}
 49→          strokeWidth={isRoofSelected ? 1.5 : DRAWING_GRAPHICS.plan.objectStrokeWidth}
 50→          vectorEffect="non-scaling-stroke"
 51→        />
 52→      )}
 53→      {plan.ridgeSegments.map((segment, index) => (
 54→        <line
 55→          key={segment.id || `roof-ridge-${index}`}
 56→          x1={segment.start.x}
 57→          y1={segment.start.y}
 58→          x2={segment.end.x}
 59→          y2={segment.end.y}
 60→          stroke={selectedType === 'roofEdge' && selectedId === segment.id ? 'var(--color-selection)' : DRAWING_GRAPHICS.plan.secondaryStroke}
 61→          strokeWidth={selectedType === 'roofEdge' && selectedId === segment.id ? 1.4 : DRAWING_GRAPHICS.plan.secondaryStrokeWidth}
 62→          vectorEffect="non-scaling-stroke"
