 69→          y1={segment.start.y}
 70→          x2={segment.end.x}
 71→          y2={segment.end.y}
 72→          stroke={selectedType === 'roofEdge' && selectedId === segment.id ? 'var(--color-selection)' : DRAWING_GRAPHICS.plan.secondaryStroke}
 73→          strokeWidth={selectedType === 'roofEdge' && selectedId === segment.id ? 1.4 : DRAWING_GRAPHICS.plan.secondaryStrokeWidth}
