134→            strokeWidth={selectedType === 'drain' && selectedId === drain.id ? 1.4 : DRAWING_GRAPHICS.plan.markerStrokeWidth}
135→            vectorEffect="non-scaling-stroke"
136→          />
137→          <circle
138→            cx={drain.center.x}
139→            cy={drain.center.y}
140→            r={drain.innerRadius}
141→            fill="none"
142→            stroke={DRAWING_GRAPHICS.plan.secondaryStroke}
143→            strokeWidth={DRAWING_GRAPHICS.plan.secondaryStrokeWidth}
144→            vectorEffect="non-scaling-stroke"
