155→          <line
156→            x1={drain.center.x - drain.innerRadius * 0.7}
157→            y1={drain.center.y + drain.innerRadius * 0.7}
158→            x2={drain.center.x + drain.innerRadius * 0.7}
159→            y2={drain.center.y - drain.innerRadius * 0.7}
160→            stroke={DRAWING_GRAPHICS.plan.secondaryStroke}
161→            strokeWidth={DRAWING_GRAPHICS.plan.secondaryStrokeWidth}
162→            vectorEffect="non-scaling-stroke"
