181→            strokeWidth={DRAWING_GRAPHICS.plan.markerStrokeWidth}
182→            vectorEffect="non-scaling-stroke"
183→          />
184→        </g>
185→      ))}
186→      <BlueprintAnnotationLayer dimensions={[]} tags={tags} className="roof-plan-annotations" />
187→    </g>
188→  );
189→}
